import { useState, useEffect } from 'react';
import AnimatedPage from '../components/AnimatedPage';
import AuraSelect from '../components/AuraSelect';
import SortableFilterTable from '../components/SortableFilterTable';
import { ResearchSubNav } from './ResearchDashboardPage';
import { api } from '../utils/api';
import s from './ResearchPromotionPage.module.css';

const STAGES = ['LAB', 'CANDIDATE', 'SIM', 'LIVE_SMALL', 'LIVE_FULL'];
const STAGE_OPTIONS = [{ value: '', label: 'All Stages' }, ...STAGES.map(st => ({ value: st, label: st }))];
const STAGE_COLORS = { LAB: '#8B949E', CANDIDATE: '#F59E0B', SIM: '#60A5FA', LIVE_SMALL: '#A78BFA', LIVE_FULL: '#22C55E' };

function StagePipeline({ evaluations }) {
  const counts = {};
  STAGES.forEach(st => { counts[st] = 0; });
  (evaluations || []).forEach(e => {
    const stage = e.Current || e.current;
    if (stage && counts[stage] !== undefined) counts[stage]++;
  });

  return (
    <div className={s.pipeline}>
      {STAGES.map((stage, i) => (
        <div key={stage} className={s.pipelineItem}>
          <div className={s.pipelineCard} style={{ border: `1px solid ${STAGE_COLORS[stage]}40` }}>
            <div className={s.pipelineLabel} style={{ color: STAGE_COLORS[stage] }}>
              {stage.replace(/_/g, ' ')}
            </div>
            <div className={s.pipelineCount}>{counts[stage]}</div>
          </div>
          {i < STAGES.length - 1 && (
            <svg width="20" height="20" viewBox="0 0 20 20" fill="none">
              <path d="M6 10h8M11 6l4 4-4 4" stroke="#30363D" strokeWidth="1.5" strokeLinecap="round" />
            </svg>
          )}
        </div>
      ))}
    </div>
  );
}

const EVAL_COLS = [
  { key: 'Strategy', label: 'Strategy', width: 180, mono: false, filterType: 'text', filterable: true },
  { key: 'Current', label: 'Current', width: 110, render: v => (
    <span className={s.stageBadge} style={{ background: `${STAGE_COLORS[v] || '#8B949E'}20`, color: STAGE_COLORS[v] || '#8B949E' }}>
      {v}
    </span>
  ), filterType: 'select', filterable: true },
  { key: 'Next', label: 'Next', width: 110, render: v => (
    <span className={s.stageBadge} style={{ background: `${STAGE_COLORS[v] || '#8B949E'}20`, color: STAGE_COLORS[v] || '#8B949E' }}>
      {v}
    </span>
  )},
  { key: 'Fitness', label: 'Fitness', width: 80, align: 'right', render: v => (v != null ? Number(v).toFixed(1) : '--') },
  { key: 'Eligible', label: 'Eligible', width: 90, align: 'center', render: v => {
    const yes = v === 'YES' || v === true;
    return <span className={yes ? s.eligibleYes : s.eligibleNo}>{yes ? 'YES' : 'NO'}</span>;
  }, filterType: 'select', filterable: true },
  { key: 'Blockers', label: 'Blockers', width: 300, mono: false, render: v => (
    <span className={`${s.blockerText} ${v && v !== '-' ? s.blockerActive : s.blockerNone}`}>{v || '-'}</span>
  )},
];

export default function ResearchPromotionPage() {
  const [data, setData] = useState(null);
  const [stageFilter, setStageFilter] = useState('');
  const [showReqs, setShowReqs] = useState(false);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    api('/research/promotions').then(d => { setData(d); setLoading(false); });
  }, []);

  const evaluations = data?.evaluations || [];
  const requirements = data?.stage_requirements || [];
  const eligible = data?.eligible || [];

  const filtered = stageFilter
    ? evaluations.filter(e => (e.Current || '') === stageFilter)
    : evaluations;

  return (
    <AnimatedPage>
      <div className={s.page}>
        <ResearchSubNav />

        <div className={s.headerRow}>
          <h1 className={s.pageTitle}>Promotion Pipeline</h1>
          <div className={s.headerActions}>
            <span className={s.eligibleCount}>{eligible.length} eligible</span>
            <AuraSelect options={STAGE_OPTIONS} value={stageFilter} onChange={setStageFilter} placeholder="Filter stage" />
          </div>
        </div>

        {/* Stage pipeline visualization */}
        <StagePipeline evaluations={evaluations} />

        {/* Stage requirements (collapsible) */}
        <div className={s.reqsPanel}>
          <button className={s.reqsToggle} onClick={() => setShowReqs(!showReqs)}>
            <span>Stage Threshold Requirements</span>
            <span className={s.reqsArrow}>{showReqs ? '\u25B2' : '\u25BC'}</span>
          </button>
          {showReqs && requirements.length > 0 && (
            <div className={s.reqsBody}>
              <table className={s.reqsTable}>
                <thead>
                  <tr>
                    {Object.keys(requirements[0]).map(k => (
                      <th key={k} className={s.reqsTableTh}>{k}</th>
                    ))}
                  </tr>
                </thead>
                <tbody>
                  {requirements.map((row, i) => (
                    <tr key={i}>
                      {Object.entries(row).map(([k, v]) => (
                        <td key={k} className={s.reqsTableTd}>
                          {typeof v === 'number' ? v : String(v)}
                        </td>
                      ))}
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </div>

        {/* Evaluation table */}
        <h2 className={s.sectionTitle}>Evaluations ({filtered.length})</h2>
        <SortableFilterTable
          columns={EVAL_COLS}
          data={filtered}
          loading={loading}
          defaultSortKey="Fitness"
          defaultSortDir="desc"
          emptyMessage="No promotion evaluations found"
        />
      </div>
    </AnimatedPage>
  );
}
